} else {
    // MediaRecorder fallback for browsers without Web Speech API
    let mediaRecorder = null;
    let audioChunks = [];
    let isRecording = false;

    async function startMediaRecorderRecording() {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

            // Prefer webm/opus, fallback to webm
            let mimeType = 'audio/webm;codecs=opus';
            if (!MediaRecorder.isTypeSupported(mimeType)) {
                mimeType = 'audio/webm';
                if (!MediaRecorder.isTypeSupported(mimeType)) {
                    throw new Error('Browser does not support webm recording');
                }
            }

            mediaRecorder = new MediaRecorder(stream, { mimeType });
            audioChunks = [];

            mediaRecorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    audioChunks.push(event.data);
                }
            };

            mediaRecorder.onstop = async () => {
                btnMic.classList.remove('recording');
                isRecording = false;

                if (audioChunks.length === 0) {
                    console.error('No audio data captured');
                    return;
                }

                const audioBlob = new Blob(audioChunks, { type: mimeType });

                // Convert to base64 and send to STT endpoint
                try {
                    const reader = new FileReader();
                    reader.onloadend = async () => {
                        const arrayBuffer = reader.result;
                        // Convert ArrayBuffer to base64 using btoa on a binary string
                        const binaryString = new Uint8Array(arrayBuffer).reduce((acc, byte) => acc + String.fromCharCode(byte), '');
                        const base64Audio = btoa(binaryString);

                        try {
                            const response = await fetch('/api/v1/stt', {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({
                                    audio_data: base64Audio,
                                    format: 'webm'
                                })
                            });

                            if (!response.ok) {
                                const error = await response.json();
                                console.error('STT transcription failed:', error);
                                btnMic.title = 'Transcription failed - try again';
                                return;
                            }

                            const result = await response.json();
                            const transcript = result.text?.trim();

                            if (transcript) {
                                textarea.value = transcript;
                                textarea.style.height = 'auto';
                                textarea.style.height = Math.min(textarea.scrollHeight, 160) + 'px';
                                btnSend.disabled = false;
                                dispatch(transcript);
                            }
                        } catch (fetchError) {
                            console.error('STT request failed:', fetchError);
                            btnMic.title = 'STT service unavailable';
                        }
                    };
                    reader.readAsArrayBuffer(audioBlob);
                } catch (blobError) {
                    console.error('Failed to process audio blob:', blobError);
                }

                // Stop all tracks to release microphone
                stream.getTracks().forEach(track => track.stop());
            };

            mediaRecorder.start();
            btnMic.classList.add('recording');
            isRecording = true;
            btnMic.title = 'Recording... Click to stop';
        } catch (error) {
            console.error('Failed to access microphone:', error);
            btnMic.title = 'Microphone access denied or unavailable';
            btnMic.style.opacity = '0.4';
            btnMic.disabled = true;
        }
    }

    btnMic.addEventListener('click', () => {
        if (isRecording && mediaRecorder && mediaRecorder.state === 'recording') {
            mediaRecorder.stop();
        } else {
            startMediaRecorderRecording();
        }
    });
}

